class HashSet {
  constructor(size = 8) {
    this.n = size;
    this.buckets = Array.from({ length: size }, () => []);
  }
  _hash(key) {
    let h = 0;
    const s = String(key);
    for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) % this.n;
    return h;
  }
  add(key) {
    const b = this.buckets[this._hash(key)];
    for (const k of b) if (k === key) return this;
    b.push(key);
    return this;
  }
  has(key) {
    const b = this.buckets[this._hash(key)];
    for (const k of b) if (k === key) return true;
    return false;
  }
  delete(key) {
    const b = this.buckets[this._hash(key)];
    const i = b.indexOf(key);
    if (i === -1) return false;
    b.splice(i, 1);
    return true;
  }
}

