function intersect(a, b) {
  const setB = new Set(b);
  const seen = new Set();
  const out = [];
  for (const x of a) {
    if (setB.has(x) && !seen.has(x)) {
      seen.add(x);
      out.push(x);
    }
  }
  return out;
}

function longest(s) {
  const seen = new Set();
  let l = 0, best = 0;
  for (let r = 0; r < s.length; r++) {
    while (seen.has(s[r])) {
      seen.delete(s[l]);
      l++;
    }
    seen.add(s[r]);
    if (r - l + 1 > best) best = r - l + 1;
  }
  return best;
}

