function hasDupWithinK(a, k) {
  const win = new Set();
  for (let i = 0; i < a.length; i++) {
    if (win.has(a[i])) return true;
    win.add(a[i]);
    if (win.size > k) win.delete(a[i - k]);
  }
  return false;
}

